class Solution {
    public long repairCars(int[] ranks, int cars) {
        Arrays.sort(ranks);
        long l = 1, r = (long)1e14;
        while (l < r) {
            long mid = l + (r - l) / 2;
            long cnt = 0;
            for (int rank : ranks) {
                cnt += mid / (rank * rank);
            }
            if (cnt < cars) {
                l = mid + 1;
            } else {
                r = mid;
            }
        }
        return l;
    }
}
```
